| AC-3 | Original | Docs | PENDING | Waiting |
| AC-4 | Original | Review | N/A | Skipped |`;

    const result = parseQaSummary(output);
    expect(result).toEqual({
      acMet: 1,
      acTotal: 4,
      gaps: [],
      suggestions: [],
    });
  });

