    const result = parseQaSummary(output);
    expect(result).toEqual({
      acMet: 1,
      acTotal: 1,
      gaps: [
        "Missing error handling for edge case",
        "No input validation on user data",
      ],
      suggestions: ["Consider adding retry logic"],
    });
  });

