    const lines = suggestionsMatch[1].trim().split("\n");
    for (const line of lines) {
      const trimmed = line.replace(/^\s*-\s+/, "").trim();
      if (trimmed && trimmed !== "None") {
        suggestions.push(trimmed);
      }
    }
  }

  return { acMet, acTotal, gaps, suggestions };
}

